                                                                                        <script type="text/javascript">
                                                var ad_segment_id   = 'straight',
                                                    segment         = 30781,
                                                    iframe_url      = "<ins class='adsbytrafficjunky' data-spot-id='30781' data-height='250px' data-width='300px'  style='width:300px;height:250px;display:block;margin:0 auto;'></ins>";
